
import { ref,onMounted,reactive } from 'vue';
import selHead from './components/selHead.vue'
import question from './components/question.vue'
import sureDialog from './components/sureDialog.vue'
import exportPdf from './components/exportPdf.vue'
import answer from './components/answer.vue'
import { Loading,Toast } from 'vant'
import { getUrlParam1, parseTime, formatSeconds } from '@/utils/index';
import { wrong_question_delete_click, wrong_question_single_click, wrong_question_single } from './js/sensors'
import api from './service/api'
import { useRoute } from 'vue-router'
import router from '@/router';
import { ImagePreview, Image as VanImage } from 'vant';

const { sObserver } = require('@/utils/simpleObserver.js')
export default{
  components: {
    selHead,
    question,
    sureDialog,
    exportPdf,
    'van-loading':Loading,
    answer
  },
  setup(){
    const $route = useRoute() as any;
    const info = ref()
    const myTitle = ref('')
    const sureDialogRef = ref()
    const showLoading = ref(false)
    const isDel = ref(false)
    const hasTags = ref(false)
    const source = ref('')
    const beforeUrl = ref('')
    const countInfo = reactive({
      count:0,
      current_num:0
    })
    const sureInfo = reactive({
      title:'确定删除错题',
      desc:'确定删除错题吗？删除后错题数据将不恢复，请谨慎操作。',
      cancelBtn:'取消',
      sureBtn:'确定删除'
    })
    const getDetail = async (params:any)=>{
      try{
        const res = await api.getBookDetail(params)
        if (res.data.errcode === 0 && res.data.data && (res.data.data as any).current_info) {
          console.log(res.data.data)
          countInfo.count = (res.data.data as any).count
          countInfo.current_num = (res.data.data as any).current_num
          info.value = (res.data.data as any).current_info
          if(info.value.subject===2){
            hasTags.value = true
          }
          const source = getUrlParam1('source')
          if(source === '2'){
            myTitle.value = info.value.plan_name
          }else{
            let day = parseTime(info.value.date,'{m}月{d}日')
            if(day.substr(0,1) === '0') day = day.substr(1)
            if(new Date().getFullYear()>new Date(info.value.date).getFullYear()){
              day = parseTime(info.value.date,'{y}年{m}月{d}日')
            }
            myTitle.value = day
          }
          initSensor()
        }
      }catch(e){
        console.log(e)
      }
    }
    const typeRes: any = ref({
    })
    // 配置列表
    const getConfig = async ()=>{
      const token = getUrlParam1('token') || ''
      const res:any = await api.getBookConfig({ token: decodeURIComponent(token)})
      if (res.data.errcode === 0) {
        typeRes.value = res.data.data
      }
    }
    // 删除错题
    const delQuestion = async(id:number)=>{
      const query = $route.query
      showLoading.value = true
      const params = { error_book_id:id,tal_id:query.tal_id}
      window.ConnectWebViewBridgeSDK.delPdf(params,(info)=>{
        console.log('删除错题',info)
        showLoading.value = false
        if(info.code===0){
          window.ConnectWebViewBridgeSDK.refreshUrl({web_url:decodeURIComponent(beforeUrl.value)})
          goback()
        }else{
          Toast('删除失败')
        }
      })
    }
    const goback = ()=>{
      window.ConnectWebViewBridgeSDK.goback()
    }
    const delData = ()=>{
      sureDialogRef.value.showPop(true)
    }
    const cancelBtn = ()=>{
      wrong_question_delete_click('取消删除')
    }
    const sureBtn = ()=>{
      if(!showLoading.value){
        wrong_question_delete_click('确定删除')
        delQuestion(info.value.id)
      }
    }
    const exportPdfFn = ()=>{
      wrong_question_single_click('导出')
      sObserver.fire('showExport',true)
    }
    const handelMyAnswer = (answer:string,status:number)=>{
      let lastStr = ''
      try{
        if(status === 4){
          lastStr='我不会'
        }else{
          if(answer){
            const myAnswer = JSON.parse(answer)
            const type = myAnswer[0].type
            if(type===5){
              myAnswer[0].data.map((item:string)=>{
                if(item==='T'){
                  lastStr = lastStr+'✓;'
                }else{
                  lastStr = lastStr+'×;'
                }
              })
            }else{
              lastStr = '$$'+myAnswer[0].data.join(';')+'$$'
            }
          }
        }
      }catch(e){
        console.log(e)
      }
      return lastStr
    }
    const handleKnowledge = (info:any)=>{
      return info.join('>>')
    }
    const handelSourceType = (id:number)=>{
      let name = ''
      typeRes.value.source_type.map((item:any)=>{
        if(item.id === id){
          name = item.val
        }
      })
      return name
    }
    const initSensor = ()=>{
      const status = info.value.status
      const tags = info.value.tags
      const source = getUrlParam1('source')
      const status_type = status===2?'未订正':(status===1?'已订正':'无订正项')
      const source_name = source==='1'?'错题本':(source==='2'?'学情详情':'')
      const extra_type = tags&&tags.length>0?'含举一反三':'不含举一反三'
      const source_type = handelSourceType(info.value.source_type)
      const obj = {
        status_type:status_type,
        source_name: source_name,
        extra_type:extra_type,
        source_type:source_type
      }
      wrong_question_single(obj)
    }


    onMounted(async() => {
      await getConfig()
      const query = $route.query
      if(query.source === '1') isDel.value = true
      const params = {
        subject_id:Number(query.subject_id),
        grade_id:query.grade_id,
        date:query.date,
        current_id:Number(query.current_id),
        token:query.token,
        tal_id:query.tal_id
      } as any
      source.value = query.source
      if(query.source === '2') params.plan_id = query.plan_id
      if(query.beforeUrl) beforeUrl.value = query.beforeUrl
      getDetail(params)
    })
    return{
      info,
      typeRes,
      myTitle,
      sureInfo,
      countInfo,
      hasTags,
      isDel,
      goback,
      delData,
      sureDialogRef,
      cancelBtn,
      sureBtn,
      showLoading,
      exportPdfFn,
      handelMyAnswer,
      formatSeconds,
      handleKnowledge,
      handelSourceType,
      source,
      beforeUrl
    }
  }
}
