import sensors from '@/utils/sensors';
import { getUrlParam1 } from '@/utils/index';

export const wrong_question_single_click = (type:string) => {
  const current_id = getUrlParam1('current_id')
  const source = getUrlParam1('source')
  if(current_id){
    sensors.track('wrong_question_single_click', {
      source_name: source==='1'?'错题本':(source==='2'?'学情详情':''),
      type:type
    })
  }else{
    sensors.track('wrong_question_list_click', {
      source_name: source==='1'?'错题本':(source==='2'?'学情详情':''),
      type:type
    })
  }
};
