
import { ref, onMounted, computed, reactive, watch } from 'vue';
import { ImagePreview, Image as VanImage } from 'vant';

import "@/utils/mathjax"; // 必须在引入mathjax前引入mathjax的配置文件
import "mathjax/es5/tex-svg-full"; // 使用 tex-svg

export default {
  props: ['answer', 'question_info', 'source_type'],
  components: {
    VanImage
  },

  setup(props: any) {
    const logicQuesTypeId = computed(
      () => props.question_info?.logicQuesTypeId
    );

    const questionChildList = computed(() => {
      if (props.question_info.childList) {
        return props.question_info.childList.map((item: any) => ({
          queId: item.queId,
          logicQuesTypeId: item.logicQuesTypeId,
          rootId: item.rootId
        }));
      } else {
        return [];
      }
    });

    const ansList = computed(() => {
      const t = JSON.parse(props.answer.answer || '[]');
      const temp = Array.isArray(t) ? t : [t];


      // fix 解答题 在旧版本学习机 返回数据异常
      if (temp.length > 0 && !temp[0].data && logicQuesTypeId.value === '8') {
        return [
          {
            type: logicQuesTypeId.value,
            data: temp,
            bkWriteImages: []
          }
        ];
      }

      if (
        temp.length > 0 &&
        logicQuesTypeId.value === '9' &&
        questionChildList.value.length > 0
      ) {
        // fix 复合题 answer 数据不完整，导致答案序号和内容对应错误
        let tmpRes: any[] = [];
        questionChildList.value.forEach((item: any) => {
          const filter = temp.filter((t: any) => t.queId === item.queId);
          if (filter.length > 0) {
            tmpRes.push(...filter.map(i => {
              return {
                ...i,
                bkWriteImages: Object.values(i.bkWriteImages)
              }
            }));
          } else {
            // 如果没有匹配到，端上没有传递回来，这里手动构造
            tmpRes.push({
              data: [],
              queId: item.queId,
              type: item.logicQuesTypeId,
              rootId: item.rootId,
              bkWriteImages: Object.values(item.bkWriteImages)
            });
          }
        });

        return tmpRes;
      }

      if (props.source_type === 4) {
        // 线下题  answer 结构不同，前端这里负责打平
        return temp.map((item: any) => {
          return {
            type: 8,
            data: item.images,
            bkWriteImages: Object.values(item.bkWriteImages)
          };
        });
      }

      // 分类题
      if (logicQuesTypeId.value === '14') {
        const tmpRes: any[] = []
        temp[0].data.forEach((da: any) => {
          tmpRes.push({
            type: 14,
            data: da,
          });
        });
        return tmpRes
      }

      return temp;
    });

    console.log('ansList', ansList);

    // 0未做 1 正确 2 错误 3 半对 4我不会
    const status = computed(() => props.answer.status);


    // 只有解答题有图片 type===8
    const hasImgs = ref([8]);
    const isHasImgs = (type: number) => hasImgs.value.includes(Number(type));

    const previewImageHandle = (images: string[] | Record<string, string>, startPosition = 1) => {

      if (Array.isArray(images)) {
        ImagePreview({
          images,
          startPosition,
        });
      } else {
        ImagePreview({
          images: Object.values(images),
          startPosition: Number(startPosition),
        });
      }
    };

    const getContentStatusIconByStatus = (status: number) => {
      // 0未做 1 正确 2 错误 3 半对 4 我不会
      const config: Record<string, any> = {
        0: {
          url: '',
          text: '未做'
        },
        1: {
          url: 'https://static0.xesimg.com/xpp-parent-fe/parentBookErrors/answer_t.png',
          text: '正确'
        },
        2: {
          url: 'https://static0.xesimg.com/xpp-parent-fe/parentBookErrors/answer_f.png',
          text: '错误'
        },
        3: {
          url: 'https://static0.xesimg.com/xpp-parent-fe/parentBookErrors/answer_tf.png',
          text: '半对'
        },
        4: {
          url: '',
          text: '我不会'
        }
      };

      return config[status] || '';
    };

    const genContentItem = (item: any) => {
      const { type: quesType, data = [] } = item;

      const type = Number(quesType)
      console.log('getItem====>', type, data)

      switch (type) {
        case 5:
          return data
            .map((item: string) => {
              return item === 'T' ? '✓' : '×';
            })
            .join('')
        case 12:
          return data
            .map((item: string) => {
              // 此时item 为音频链接
              return `<audio controls src="${item}"></audio>`;
            })
            .join('')
        default:
          return data.map((da: any) => {
            const svg = window.MathJax.tex2svg(da, { display: true });
            svg.style.margin = '0'
            const rectE = svg.querySelector('rect');
            if (rectE) {
              rectE.parentNode.removeChild(rectE);
            }
            const textE = svg.querySelector('text');
            if (textE) {
              textE.style.fill = 'rgba(0, 0, 0, 0.6)';
              textE.style.stroke = 'rgba(0, 0, 0, 0.6)';
            }
            return window.MathJax.startup.adaptor.outerHTML(svg);
          }).join('&nbsp;;&nbsp;');
      }
    };
    return {
      ansList,
      status,
      logicQuesTypeId,
      isHasImgs,
      previewImageHandle,
      getContentStatusIconByStatus,
      genContentItem
    };
  }
};
